package main

import "fmt"

// We define our custom type right here
type User struct {
    Name    string
    Age     int
    IsAdmin bool
}

func main() {
    // Creating a variable of our new 'User' type!
    playerOne := User{
        Name: "Alice",
        Age: 25,
        IsAdmin: true,
    }

    // Accessing fields using a dot
    fmt.Println("Player Name:", playerOne.Name)
}
